@media print {
  @page {
    size: A4;
    margin: 0;
  }

  body {
    margin: 0;
    padding: 0;
    font-family: sans-serif;
  }

  .page {
    position: relative;
    width: 210mm;
    height: 297mm;
    page-break-after: always;
    overflow: hidden;
  }

  .bg-image {
    position: absolute;
    top: 0;
    left: 0;
    width: 210mm;
    height: 297mm;
    z-index: -1;
  }

  .bg-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
  }

  .page-content {
    position: relative;
    z-index: 1;
    padding: 30mm 20mm;
    height: 100%;
    box-sizing: border-box;
  }
}

